	top: -0.75em;
	text-align: left;
}

.locmap .pv > div {
	display: inline;
	padding: 1px;
}

.locmap .pl > div {
	display: inline; /* inline does not impact floated elements */
	padding: 1px;
	float: right;
}

.locmap .pr > div {
	display: inline; /* inline does not impact floated elements */
	padding: 1px;
	float: left;
}

